INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(16, 6, 1, 'comprehension',
'According to the passage, what is the primary ethical concern surrounding germline gene editing?',
'第3段落で、生殖細胞系列編集の最も警戒すべき点として、修正が「将来の世代に受け継がれる」こと、ゲノム相互作用の理解が「そのような介入の長期的影響を予測するにはあまりにも初歩的」であること、そして修正が「事実上逆転不可能な新たな脆弱性をヒト遺伝子プールに導入する恐れ」があることが述べられている。選択肢3が「将来世代に恒久的に受け継がれる予測不能な結果を生む可能性がある」と正確に要約している。選択肢1は「コストが高い」で倫理的懸念ではない。選択肢2は「現在の患者にとって効果がない」で本文は治療効果を認めている。選択肢4は「動物実験の倫理」で本文の主論点ではない。',
3),
(17, 6, 2, 'comprehension',
'What does the passage suggest about the decreasing cost of CRISPR technology?',
'第5段落で、CRISPRツールのコスト減少により技術が「エリート研究機関を超えて小規模な研究室やアマチュアのバイオハッキングコミュニティにまで移行」していると述べられている。この民主化はイノベーション促進の可能性がある一方、「深刻なバイオセキュリティ上の懸念を引き起こす」と指摘されている。選択肢2が「より広いアクセスを可能にするがバイオセキュリティリスクも生む」と正確に対応している。選択肢1は「純粋に肯定的」で本文はリスクも指摘。選択肢3は「研究の質を下げる」で本文の論点と異なる。選択肢4は「政府規制が追いついている」で本文はむしろ逆。',
2),
(18, 6, 3, 'fill_in_blank',
'Choose the best option to fill in the blank [BLANK] in the passage.',
'空所は第3段落にあり、「ある遺伝的文脈では無害に見える編集が、別の文脈では[BLANK]を引き起こす可能性がある」という文脈。前文で「介入の長期的影響を予測するにはあまりにも初歩的」と述べ、後文で「新たな脆弱性をヒト遺伝子プールに導入する恐れ」とあるので、予期せぬ有害な連鎖反応を表す表現が入る。選択肢1が「予期せぬ有害な連鎖反応」で最も適切。選択肢2は「わずかな改善」で文脈の深刻さと合わない。選択肢3は「同一の結果」で無害に見えるとの対比にならない。選択肢4は「即座だが可逆的な副作用」で「逆転不可能」との後続文と矛盾。',
1);

